//! RISC-V kernel entry point for the contest build.

#![deny(missing_docs)]
#![deny(warnings)]
#![no_std]
#![no_main]

use core::arch::global_asm;

#[macro_use]
mod console;
mod arch;
mod drivers;
mod fs;
mod lang_items;
mod loader;
mod platform;
mod sbi;
mod syscall;
mod task;
mod trap;

global_asm!(include_str!("entry.asm"));

/// Clear BSS segment.
fn clear_bss() {
    unsafe extern "C" {
        safe fn sbss();
        safe fn ebss();
    }
    unsafe {
        let start = sbss as *const () as usize;
        let end = ebss as *const () as usize;
        core::slice::from_raw_parts_mut(start as *mut u8, end - start).fill(0);
    }
}

/// Rust entry point of the RISC-V kernel.
#[unsafe(no_mangle)]
pub fn rust_main() -> ! {
    clear_bss();
    println!("[kernel] OSKernel2026 RISC-V booting");
    trap::init();
    platform::run();
}

//! RISC-V CSR helpers used by the contest kernel.

use core::arch::asm;

/// Supervisor previous privilege bit in `sstatus`.
pub const SSTATUS_SPP: usize = 1 << 8;
/// Supervisor interrupt enable bit in `sstatus`.
pub const SSTATUS_SPIE: usize = 1 << 5;
/// Floating-point unit state bits in `sstatus`.
///
/// 平台上的 LTP 测试库在清理/格式化路径里可能执行 `fsd/flw/fcvt` 等浮点指令。
/// 当前内核没有懒保存 FPU 上下文，直接把 FS 置为 Dirty，避免用户态浮点指令
/// 被硬件按非法指令处理。
pub const SSTATUS_FS_DIRTY: usize = 0b11 << 13;

/// Read `sstatus`.
#[inline]
pub fn read_sstatus() -> usize {
    let bits: usize;
    unsafe {
        asm!("csrr {}, sstatus", out(reg) bits);
    }
    bits
}

/// Write `stvec`.
#[inline]
pub unsafe fn write_stvec(addr: usize) {
    unsafe {
        asm!("csrw stvec, {}", in(reg) addr);
    }
}

/// Read `scause`.
#[inline]
pub fn read_scause() -> usize {
    let bits: usize;
    unsafe {
        asm!("csrr {}, scause", out(reg) bits);
    }
    bits
}

/// Read `stval`.
#[inline]
pub fn read_stval() -> usize {
    let bits: usize;
    unsafe {
        asm!("csrr {}, stval", out(reg) bits);
    }
    bits
}

/// Read the RISC-V `time` CSR.
#[inline]
pub fn read_time() -> usize {
    let bits: usize;
    unsafe {
        asm!("csrr {}, time", out(reg) bits);
    }
    bits
}

/// Write `satp`.
#[inline]
pub unsafe fn write_satp(bits: usize) {
    unsafe {
        asm!("csrw satp, {}", in(reg) bits);
        asm!("sfence.vma");
    }
}

//! RISC-V trap handling for user-mode contest programs.

mod context;

use crate::arch::{read_scause, read_stval, write_stvec};
use crate::syscall::{
    SyscallResult, deliver_trap_signal, finish_child_after_exit, maybe_deliver_signal, syscall,
};
use crate::task;
use core::arch::global_asm;

global_asm!(include_str!("trap.S"));

/// Initialize `stvec`.
pub fn init() {
    unsafe extern "C" {
        safe fn __alltraps();
    }
    unsafe {
        write_stvec(__alltraps as *const () as usize);
    }
}

/// Handle a trap from user space.
#[unsafe(no_mangle)]
pub fn trap_handler(cx: &mut TrapContext) -> &mut TrapContext {
    let scause = read_scause();
    let stval = read_stval();
    let interrupt_bit = 1usize << (usize::BITS as usize - 1);
    let is_interrupt = scause & interrupt_bit != 0;
    let cause = scause & !interrupt_bit;
    if is_interrupt {
        // 当前评测先不启用异步 timer 投递；时钟中断直接安全返回用户态。
        return cx;
    }
    match cause {
        8 => {
            cx.sepc += 4;
            match syscall(
                cx.x[17],
                [cx.x[10], cx.x[11], cx.x[12], cx.x[13], cx.x[14], cx.x[15]],
                cx,
            ) {
                SyscallResult::Value(result) => {
                    // `sys_exit` records an exit request; the real handoff happens
                    // here so syscall implementations stay regular functions.
                    if let Some(exit_code) = task::take_pending_exit() {
                        if let Some(parent) = finish_child_after_exit(exit_code) {
                            return parent;
                        }
                        return task::exit_context(exit_code);
                    }
                    cx.x[10] = result as usize;
                    maybe_deliver_signal(cx);
                }
                SyscallResult::Switch(next) => return next,
            }
        }
        12 | 13 | 15 if task::handle_user_page_fault(stval, cause == 15, cause == 12) => {
            // brk/mmap 匿名页采用懒分配；第一次用户态访问只需要补页后重试。
            return cx;
        }
        1 | 2 | 3 | 5 | 7 | 12 | 13 | 15 => {
            if cause == 12 && crate::syscall::should_treat_low_exec_fault_as_exit(cx.sepc, stval) {
                if let Some(parent) = finish_child_after_exit(0) {
                    return parent;
                }
                return task::exit_context(0);
            }
            if deliver_trap_signal(cx, fatal_trap_signal(cause) as usize) {
                return cx;
            }
            if let Some(parent) = finish_child_after_exit(-fatal_trap_signal(cause)) {
                return parent;
            }
            println!(
                "[kernel] user trap cause {}, sepc {:#x}, stval {:#x}; terminating current test",
                cause, cx.sepc, stval
            );
            // 用户态 abort 会用 ebreak 触发 breakpoint trap；缺动态库或坏函数指针
            // 也可能造成取指/访存错误。这些都只应判当前测试失败，不能让内核 panic。
            return task::exit_context(-1);
        }
        _ => panic!("unsupported trap cause {}, stval {:#x}", cause, stval),
    }
    cx
}

fn fatal_trap_signal(cause: usize) -> i32 {
    match cause {
        // 非法指令按 SIGILL；断点按 SIGTRAP；访存/取指错误按 SIGSEGV。
        2 => 4,
        3 => 5,
        _ => 11,
    }
}

pub use context::TrapContext;

use crate::arch::{SSTATUS_FS_DIRTY, SSTATUS_SPIE, SSTATUS_SPP, read_sstatus};

/// Trap Context
#[derive(Clone, Copy)]
#[repr(C)]
pub struct TrapContext {
    /// general regs[0..31]
    pub x: [usize; 32],
    /// CSR sstatus      
    pub sstatus: usize,
    /// CSR sepc
    pub sepc: usize,
}

impl TrapContext {
    /// set stack pointer to x_2 reg (sp)
    pub fn set_sp(&mut self, sp: usize) {
        self.x[2] = sp;
    }
    /// init app context
    pub fn app_init_context(entry: usize, sp: usize) -> Self {
        let mut sstatus = read_sstatus();
        sstatus &= !SSTATUS_SPP;
        // RISC-V 只有在 sstatus.FS 非 Off 时才允许用户态执行浮点指令。
        // LTP/libc 的格式化与统计路径会使用浮点寄存器，先采用始终开启的
        // 简化策略，后续如需多任务抢占再补完整 FPU 上下文保存。
        sstatus |= SSTATUS_SPIE | SSTATUS_FS_DIRTY;
        let mut cx = Self {
            x: [0; 32], // 初始化所有通用寄存器为 0
            sstatus,
            sepc: entry, // entry point of app
        };
        cx.set_sp(sp); // app's user stack pointer
        cx // return initial Trap Context of app
    }
}

//! The panic handler

use crate::sbi::shutdown;
use core::panic::PanicInfo;

#[panic_handler]
fn panic(info: &PanicInfo) -> ! {
    if let Some(location) = info.location() {
        println!(
            "[kernel] Panicked at {}:{} {}",
            location.file(),
            location.line(),
            info.message()
        );
    } else {
        println!("[kernel] Panicked: {}", info.message());
    }
    shutdown(true)
}

