//! Minimal user address space and enter/return path for contest ELFs.
//!
//! The `task` layer owns user-memory setup and the supervisor-to-user handoff,
//! keeping execution state separate from the filesystem and contest harness.
#![allow(static_mut_refs)]

use crate::arch::{SSTATUS_FS_DIRTY, SSTATUS_SPIE, SSTATUS_SPP, read_sstatus, write_satp};
use crate::trap::TrapContext;
use core::arch::{asm, global_asm};
use core::mem::size_of;
use core::sync::atomic::{Ordering, compiler_fence};

const PAGE_SIZE: usize = 4096;
const LARGE_PAGE_SIZE: usize = 2 * 1024 * 1024;
const SATP_MODE_SV39: usize = 8usize << 60;

const PTE_V: u64 = 1 << 0;
const PTE_R: u64 = 1 << 1;
const PTE_W: u64 = 1 << 2;
const PTE_X: u64 = 1 << 3;
const PTE_U: u64 = 1 << 4;
const PTE_A: u64 = 1 << 6;
const PTE_D: u64 = 1 << 7;

// 用户虚拟空间可以大于实际可用帧池；匿名页采用懒分配后，iozone 的
// `-T -t 4` 需要同时保留一百多 MB malloc/mmap 地址。上限放到 MMIO
// 窗口之前，既避开 0x1000_0000 设备区，也不增加真实物理内存消耗。
const USER_VA_LIMIT: usize = 0x0e80_0000;
const USER_STACK_TOP: usize = USER_VA_LIMIT;
// libcbench 的 regex_search 会在用户栈上放置约 260KB 的局部缓冲区；LTP
// writetest 会连续使用两个 1MB 栈上 I/O 缓冲。默认栈给到 4MB，覆盖这些
// 大局部数组路径，同时仍不明显压缩当前用户虚拟地址空间。
const USER_STACK_PAGES: usize = 1024;
const USER_VPN_COUNT: usize = USER_VA_LIMIT / PAGE_SIZE;
const USER_L0_TABLE_COUNT: usize = (USER_VA_LIMIT + LARGE_PAGE_SIZE - 1) / LARGE_PAGE_SIZE;
// brk 兼容 basic 用例时固定从 0x100000 起步；匿名 mmap 单独从更高地址
// 分配。libcbench 的 malloc 会把 brk 推到几十 MB，所以 mmap 区需要再往上
// 挪，避免两类分配互相覆盖元数据。
const USER_DYNAMIC_BASE: usize = 0x400_0000;
// 信号 restorer trampoline 单独放在栈区下方一页，避免和普通 mmap/堆冲突。
const USER_SIGNAL_TRAMPOLINE: usize = USER_STACK_TOP - USER_STACK_PAGES * PAGE_SIZE - PAGE_SIZE;
// LTP growfiles 这类 direct ELF case 会携带 20+ 个短参数；用户栈空间充足，
// 这里放宽直接加载路径的 argv 上限，不影响 execve 侧的 trap 栈缓冲。
const MAX_USER_ARGS: usize = 32;
const MAX_USER_ENVS: usize = 16;
const DEFAULT_USER_ENV: [&str; 2] = [
    "PATH=/musl/ltp/testcases/bin:/glibc/ltp/testcases/bin:/ltp/testcases/bin:/bin:/sbin:/usr/bin:/usr/sbin:.",
    "LTPROOT=/ltp",
];
const MAX_TOP_MMAP_HOLES: usize = 128;

const MMIO_BASE: usize = 0x1000_0000;
const KERNEL_IDENTITY_BASE: usize = 0x8000_0000;
const KERNEL_IDENTITY_SIZE: usize = 128 * 1024 * 1024;
const MAX_USER_FRAMES: usize = 20 * 1024 - 4;
const FORK_KEEP_FRAME: u16 = u16::MAX - 1;
// glibc pthread 收尾路径会经过 stdio、动态库清理和 libgcc unwind 探测，单次
// 线程 trap frame 放在独立 kernel stack 上，避免不同 pthread 互相覆盖。
// iozone-glibc 的 pthread throughput 收尾会经过 libgcc unwind/stdio 清理，
// 16KB 偶发把线程恢复地址打成 0；32KB 消除该路径 trap。mmap 顶端空洞
// 已随 fork 快照回滚，避免扩大静态栈后再次影响 libcbench 的 pthread 用例。
const KERNEL_STACK_SIZE: usize = 4096 * 8;
// BusyBox musl 是较大的静态 PIE，shell 每次 fork/vfork 前需要保存父进程
// 用户地址空间。iozone throughput 会在 fork 前分配数 MB 测试缓冲，
// 因此快照池给到 24MB；仍保持小步扩容，避免明显挤压 128MB QEMU 内存预算。
const MAX_FORK_FRAMES: usize = 4800;
// LTP 的测试库会先 fork 出测试主体，部分用例内部还会 SAFE_FORK 子进程。
// eager fork 因此需要保存多层父 trap frame 和多层内存快照元数据；真实页内容
// 仍共用下面的 FORK_FRAMES 池，避免为嵌套 fork 额外复制 24MB 静态内存。
const MAX_EAGER_FORK_DEPTH: usize = 3;
const MAX_PENDING_THREADS: usize = 63;
const MAX_READY_THREADS: usize = 64;

pub(crate) struct UserStackAux {
    pub entry: usize,
    pub phdr: usize,
    pub phent: usize,
    pub phnum: usize,
    pub base: usize,
}

global_asm!(
    r#"
    .section .text
    .globl __enter_user
