    pub(crate) size: u64,
}

/// Mounted read-only EXT4 filesystem.
pub(crate) struct Ext4 {
    device: VirtioBlock,
    block_size: usize,
    inodes_per_group: u32,
    inode_size: usize,
    desc_size: usize,
    // Group descriptor table follows the superblock. When block size is 1KiB,
    // it starts at block 2; otherwise it starts at block 1.
    group_desc_offset: u64,
    has_64bit_desc: bool,
}

#[derive(Clone, Copy)]
struct Inode {
    mode: u16,
    size: u64,
    flags: u32,
    block: [u8; 60],
}

impl Ext4 {
    /// Mount the EXT4 image exposed as virtio block device 0.
    pub(crate) fn mount(mut device: VirtioBlock) -> Result<Self, &'static str> {
        let mut superblock = [0u8; 1024];
        read_bytes_from_device(&mut device, EXT4_SUPERBLOCK_OFFSET, &mut superblock)?;
        if read_u16(&superblock, 0x38) != EXT4_SUPER_MAGIC {
            return Err("not an ext4 filesystem");
        }

        let block_size = 1024usize << read_u32(&superblock, 0x18);
        if block_size > MAX_BLOCK_SIZE {
            return Err("ext4 block size too large");
        }
        let inode_size = read_u16(&superblock, 0x58) as usize;
        let desc_size = {
            let raw = read_u16(&superblock, 0xfe) as usize;
            if raw == 0 { 32 } else { raw }
        };
        let group_desc_offset = if block_size == 1024 {
            2 * 1024
        } else {
            block_size as u64
        };
        let feature_incompat = read_u32(&superblock, 0x60);

        Ok(Self {
            device,
            block_size,
            inodes_per_group: read_u32(&superblock, 0x28),
            inode_size,
            desc_size,
            group_desc_offset,
            has_64bit_desc: feature_incompat & EXT4_FEATURE_INCOMPAT_64BIT != 0,
        })
    }

    /// Look up one named child in a directory inode.
    pub(crate) fn lookup_child(
        &mut self,
        dir_inode_num: u32,
        target_name: &str,
    ) -> Result<Option<LookupResult>, &'static str> {
        let dir_inode = self.read_inode(dir_inode_num)?;
        if node_kind(dir_inode.mode) != NodeKind::Directory {
            return Err("lookup source is not a directory");
        }

        let mut block_buf = [0u8; MAX_BLOCK_SIZE];
        let total_blocks = div_ceil_u64(dir_inode.size, self.block_size as u64) as u32;
        for file_block in 0..total_blocks {
            // Directory contents are still regular inode data blocks; we only
            // need the linear ext4 directory-entry format here.
            let disk_block = self.extent_block_for(&dir_inode, file_block)?;
            self.read_block(disk_block, &mut block_buf[..self.block_size])?;

            let mut cursor = 0usize;
            while cursor + 8 <= self.block_size {
                let inode = read_u32(&block_buf, cursor);
                let rec_len = read_u16(&block_buf, cursor + 4) as usize;
                let name_len = block_buf[cursor + 6] as usize;
                let file_type = block_buf[cursor + 7];
                if rec_len == 0 || cursor + rec_len > self.block_size {
                    return Err("ext4 directory entry is malformed");
                }
                if inode != 0 && name_len <= rec_len.saturating_sub(8) {
                    let name_bytes = &block_buf[cursor + 8..cursor + 8 + name_len];
                    if let Ok(name) = core::str::from_utf8(name_bytes) {
                        if name == target_name {
                            let kind = match file_type {
                                1 => NodeKind::File,
                                2 => NodeKind::Directory,
                                _ => node_kind(self.read_inode(inode)?.mode),
                            };
                            return Ok(Some(LookupResult { inode, kind }));
                        }
                    }
                }
                cursor += rec_len;
            }
        }
        Ok(None)
    }

