const AVAIL_OFFSET: usize = DESC_OFFSET + core::mem::size_of::<[VirtqDesc; QUEUE_SIZE]>();
const USED_OFFSET: usize = align_up(
    AVAIL_OFFSET + core::mem::size_of::<VirtqAvail>(),
    LEGACY_QUEUE_ALIGN,
);
const QUEUE_BYTES: usize = USED_OFFSET + core::mem::size_of::<VirtqUsed>();

