static mut REQUEST_HEADER: VirtioBlkReqHeader = VirtioBlkReqHeader {
    type_: 0,
    reserved: 0,
    sector: 0,
};
static mut REQUEST_STATUS: u8 = 0xff;

#[derive(Clone, Copy, Eq, PartialEq)]
enum VirtioTransport {
    Legacy,
    Modern,
}

/// Single-queue polling block driver for virtio-blk device 0.
pub(crate) struct VirtioBlock {
    base: usize,
    transport: VirtioTransport,
    // Only one synchronous request is ever in flight, so tracking used.idx is enough.
    last_used_idx: u16,
}

impl VirtioBlock {
    /// Initialize the judge-provided virtio block device.
    pub(crate) fn new() -> Result<Self, &'static str> {
        let base = VIRTIO_MMIO_BASE;
        if mmio_read(base, VIRTIO_MMIO_MAGIC_VALUE) != VIRTIO_MAGIC {
            return Err("virtio magic mismatch");
        }
        let transport = match mmio_read(base, VIRTIO_MMIO_VERSION) {
            VIRTIO_VERSION_LEGACY => VirtioTransport::Legacy,
            VIRTIO_VERSION_MODERN => VirtioTransport::Modern,
            _ => return Err("unsupported virtio-mmio version"),
        };
        if mmio_read(base, VIRTIO_MMIO_DEVICE_ID) != VIRTIO_DEVICE_ID_BLOCK {
            return Err("virtio device 0 is not block");
        }

        unsafe {
            core::ptr::write_bytes(
                core::ptr::addr_of_mut!(QUEUE_MEMORY.0).cast::<u8>(),
                0,
                QUEUE_BYTES,
            );
            core::ptr::write_volatile(core::ptr::addr_of_mut!(REQUEST_STATUS), 0xff);
        }

        mmio_write(base, VIRTIO_MMIO_STATUS, 0);
        let mut status = VIRTIO_STATUS_ACKNOWLEDGE | VIRTIO_STATUS_DRIVER;
        mmio_write(base, VIRTIO_MMIO_STATUS, status);

        mmio_write(base, VIRTIO_MMIO_DEVICE_FEATURES_SEL, 0);
        let _device_features = mmio_read(base, VIRTIO_MMIO_DEVICE_FEATURES);
        mmio_write(base, VIRTIO_MMIO_DRIVER_FEATURES_SEL, 0);
        mmio_write(base, VIRTIO_MMIO_DRIVER_FEATURES, 0);

        mmio_write(base, VIRTIO_MMIO_QUEUE_SEL, 0);
        if mmio_read(base, VIRTIO_MMIO_QUEUE_NUM_MAX) < QUEUE_SIZE as u32 {
            return Err("virtio queue too small");
        }
        mmio_write(base, VIRTIO_MMIO_QUEUE_NUM, QUEUE_SIZE as u32);

        let queue_base = queue_base_addr();
        let desc_addr = queue_base + DESC_OFFSET as u64;
        let avail_addr = queue_base + AVAIL_OFFSET as u64;
        let used_addr = queue_base + USED_OFFSET as u64;

        match transport {
            VirtioTransport::Legacy => {
                mmio_write(base, VIRTIO_MMIO_GUEST_PAGE_SIZE, LEGACY_PAGE_SIZE as u32);
                mmio_write(base, VIRTIO_MMIO_QUEUE_ALIGN, LEGACY_QUEUE_ALIGN as u32);
                mmio_write(
                    base,
                    VIRTIO_MMIO_QUEUE_PFN,
                    (queue_base / LEGACY_PAGE_SIZE as u64) as u32,
                );
            }
            VirtioTransport::Modern => {
                status |= VIRTIO_STATUS_FEATURES_OK;
                mmio_write(base, VIRTIO_MMIO_STATUS, status);
                if mmio_read(base, VIRTIO_MMIO_STATUS) & VIRTIO_STATUS_FEATURES_OK == 0 {
                    mmio_write(base, VIRTIO_MMIO_STATUS, status | VIRTIO_STATUS_FAILED);
                    return Err("virtio feature negotiation failed");
                }

                mmio_write(base, VIRTIO_MMIO_QUEUE_DESC_LOW, desc_addr as u32);
                mmio_write(base, VIRTIO_MMIO_QUEUE_DESC_HIGH, (desc_addr >> 32) as u32);
                mmio_write(base, VIRTIO_MMIO_QUEUE_AVAIL_LOW, avail_addr as u32);
                mmio_write(
                    base,
                    VIRTIO_MMIO_QUEUE_AVAIL_HIGH,
                    (avail_addr >> 32) as u32,
                );
                mmio_write(base, VIRTIO_MMIO_QUEUE_USED_LOW, used_addr as u32);
                mmio_write(base, VIRTIO_MMIO_QUEUE_USED_HIGH, (used_addr >> 32) as u32);
                mmio_write(base, VIRTIO_MMIO_QUEUE_READY, 1);
