        mmio_write(base, VIRTIO_MMIO_STATUS, status);
        mmio_write(base, VIRTIO_MMIO_INTERRUPT_ACK, u32::MAX);

        Ok(Self {
            base,
            transport,
            last_used_idx: 0,
        })
    }

