/// Run BusyBox's official script while hiding unrelated top-level suite
/// directories from `du .` and `find .`.
pub(crate) fn run_busybox_program_with_args(
    fs: &mut Ext4,
    inode_num: u32,
    args: &[&str],
    cwd_inode: u32,
) -> Result<i32, &'static str> {
    run_user_program_with_args_inner(fs, inode_num, args, cwd_inode, false, true)
}

fn run_user_program_with_args_inner(
    fs: &mut Ext4,
    inode_num: u32,
    args: &[&str],
    cwd_inode: u32,
    preserve_overlay: bool,
    busybox_root_filter: bool,
) -> Result<i32, &'static str> {
    let (entry, user_sp, initial_brk) =
        load_user_program_with_args_at(fs, inode_num, args, cwd_inode)?;
    if preserve_overlay {
        syscall::reset_for_program_preserve_overlay(fs, cwd_inode, initial_brk);
    } else {
        syscall::reset_for_program(fs, cwd_inode, initial_brk);
    }
    if let Some(name) = args.first() {
        syscall::configure_loaded_program(name);
    }
    if busybox_root_filter {
        syscall::configure_busybox_root_filter();
    }
    Ok(task::run(entry, user_sp))
}

pub(crate) fn load_user_program_with_args_at(
    fs: &mut Ext4,
    inode_num: u32,
    args: &[&str],
    runtime_root_inode: u32,
) -> Result<(usize, usize, usize), &'static str> {
    load_user_program_with_args_env_at(fs, inode_num, args, &[], runtime_root_inode)
}

pub(crate) fn load_user_program_with_args_env_at(
    fs: &mut Ext4,
    inode_num: u32,
    args: &[&str],
    env: &[&str],
    runtime_root_inode: u32,
) -> Result<(usize, usize, usize), &'static str> {
    task::prepare_address_space()?;
    let main = load_elf_image(fs, inode_num, DYNAMIC_MAIN_BASE, true)?;
    let (entry, at_base, loaded_end) = if main.interp_len == 0 || !main.needs_interpreter {
        (main.entry, 0, main.end)
    } else {
        let interp_inode =
            resolve_interpreter_inode(fs, runtime_root_inode, &main.interp[..main.interp_len])?;
        let interp = load_elf_image(fs, interp_inode, DYNAMIC_LINKER_BASE, false)?;
        (interp.entry, interp.base, main.end.max(interp.end))
    };

    // basic 自带 crt 只需要 argc/argv；lua、busybox、动态 musl 还会读取
    // auxv，所以 loader 在这里把主程序头和动态链接器基址一并传给用户栈。
    let aux = task::UserStackAux {
        entry: main.entry,
        phdr: main.phdr,
        phent: main.phent,
        phnum: main.phnum,
        base: at_base,
    };
    let user_sp = if env.is_empty() {
        task::build_user_stack_with_args(args, aux)?
    } else {
        task::build_user_stack_with_args_env(args, env, aux)?
    };
    Ok((entry, user_sp, align_up(loaded_end)))
}

fn load_elf_image(
    fs: &mut Ext4,
