//! batch subsystem 
//! 批处理子系统。定义了内核栈和用户栈的结构，以及一个 AppManager 结构体来管理应用程序的信息。

use crate::sbi::shutdown;
use crate::sync::UPSafeCell;
use crate::trap::TrapContext;
use core::arch::asm;
use lazy_static::*;

const USER_STACK_SIZE: usize = 4096 * 2; // 用户栈的大小，设置为 8KB，以便在运行应用程序时能够处理足够的用户级别的调用和函数执行
const KERNEL_STACK_SIZE: usize = 4096 * 2; // 内核栈的大小，设置为 8KB，以便在运行应用程序时能够处理足够的内核级别的调用和中断处理
const MAX_APP_NUM: usize = 16; // 最大应用程序数量，链接器会在 link_app.S 中定义这个符号，并将其值设置为实际的最大应用程序数量，以便在运行时进行检查和管理
const APP_BASE_ADDRESS: usize = 0x80400000; // 应用程序的基地址，链接器会在 link_app.S 中定义这个符号，并将其值设置为应用程序的加载地址
const APP_SIZE_LIMIT: usize = 0x20000; // 所有应用程序的大小限制为 128KB

#[repr(align(4096))]  // 将 KernelStack 结构体的对齐方式设置为 4096 字节，以确保内核栈在内存中的起始地址是 4096 的倍数，以满足 RISC-V 架构对栈的对齐要求
struct KernelStack {
    data: [u8; KERNEL_STACK_SIZE],
}

#[repr(align(4096))]
struct UserStack {
    data: [u8; USER_STACK_SIZE],
}

static KERNEL_STACK: KernelStack = KernelStack {
    data: [0; KERNEL_STACK_SIZE],
};
static USER_STACK: UserStack = UserStack {
    data: [0; USER_STACK_SIZE],
};

impl KernelStack {
    fn get_sp(&self) -> usize {
        self.data.as_ptr() as usize + KERNEL_STACK_SIZE
    }
    pub fn push_context(&self, cx: TrapContext) -> &'static mut TrapContext {
        let cx_ptr = (self.get_sp() - core::mem::size_of::<TrapContext>()) as *mut TrapContext;
        unsafe {
            *cx_ptr = cx;
        }
        unsafe { cx_ptr.as_mut().unwrap() }
    }
}

impl UserStack {
    fn get_sp(&self) -> usize {
        self.data.as_ptr() as usize + USER_STACK_SIZE
    }
}

// 结构体 AppManager 用于管理应用程序的信息，包括应用程序的数量、当前正在运行的应用程序的索引以及每个应用程序的起始地址。
struct AppManager {
    num_app: usize, // 应用程序的数量
    current_app: usize, // 当前正在运行的应用程序的索引
    app_start: [usize; MAX_APP_NUM + 1], // 每个应用程序的起始地址及最后一个应用程序的结束地址
}

impl AppManager {
    // 打印应用程序的信息，包括应用程序的数量以及每个应用程序的起始地址和结束地址。
    pub fn print_app_info(&self) {
        println!("[kernel] num_app = {}", self.num_app); 
        for i in 0..self.num_app {
            println!(
                "[kernel] app_{} [{:#x}, {:#x})", // :表示格式化输出，#表示显示前缀，x表示以十六进制格式输出
                i,
                self.app_start[i], 
                self.app_start[i + 1]
            );
        }
    }

    // 加载指定 ID 的应用程序，将其代码从链接器定义的地址复制到指定的应用程序基地址，并执行指令内存屏障以确保后续的指令获取能够看到之前的写入。
    fn load_app(&self, app_id: usize) {
        if app_id >= self.num_app {
            println!("All applications completed!");
            shutdown(false);
        }
        println!("[kernel] Loading app_{}", app_id); 
        unsafe {
            // clear app area
            core::slice::from_raw_parts_mut(APP_BASE_ADDRESS as *mut u8, APP_SIZE_LIMIT).fill(0); // 将应用程序基地址开始的内存区域清零，大小为 APP_SIZE_LIMIT，以确保加载新的应用程序之前该区域是干净的。
            // 复制应用程序代码
            let app_src = core::slice::from_raw_parts(
                self.app_start[app_id] as *const u8, // 获取指定 ID 的应用程序的起始地址，并将其转换为指向 u8 的指针，以便读取应用程序的代码
                self.app_start[app_id + 1] - self.app_start[app_id], // 计算指定 ID 的应用程序的大小，即结束地址减去起始地址，以便正确地复制应用程序的代码
            );
            // 获取应用程序基地址，并将其转换为指向 u8 的可变指针，以便将应用程序的代码复制到该地址，同时指定复制的长度为 app_src 的长度，以确保正确地复制整个应用程序的代码
            let app_dst =
                core::slice::from_raw_parts_mut(APP_BASE_ADDRESS as *mut u8, app_src.len()); 
            app_dst.copy_from_slice(app_src); // 将 app_src 中的代码复制到 app_dst 中，使用 copy_from_slice 来进行复制，以确保正确地将应用程序的代码加载到指定的内存区域中
            // Memory fence about fetching the instruction memory
            // It is guaranteed that a subsequent instruction fetch must
            // observes all previous writes to the instruction memory.
            // Therefore, fence.i must be executed after we have loaded
            // the code of the next app into the instruction memory.
            // See also: riscv non-priv spec chapter 3, 'Zifencei' extension.
            asm!("fence.i");
        }
    }

    // 获取当前正在运行的应用程序的索引，以便在运行应用程序时能够正确地加载和管理应用程序。
    pub fn get_current_app(&self) -> usize {
        self.current_app
    }

    // 将当前正在运行的应用程序的索引加 1，以便在运行下一个应用程序时能够正确地加载和管理应用程序。
    pub fn move_to_next_app(&mut self) {
        self.current_app += 1;
    }
}

// 初始化AppManager全局实例
lazy_static! {
    static ref APP_MANAGER: UPSafeCell<AppManager> = unsafe {
        UPSafeCell::new({
            unsafe extern "C" {
                safe fn _num_app(); // 应用程序的数量，链接器会在 link_app.S 中定义这个符号，并将其值设置为应用程序的数量
            }
            let num_app_ptr = _num_app as usize as *const usize; // 获取 _num_app 的地址，并将其转换为指向 usize 的指针，以便读取应用程序的数量
            let num_app = num_app_ptr.read_volatile(); // 从 num_app_ptr 指向的地址读取应用程序的数量，使用 read_volatile 是因为这个值可能会被链接器在运行时修改
            let mut app_start: [usize; MAX_APP_NUM + 1] = [0; MAX_APP_NUM + 1]; // 定义一个数组 app_start，用于存储每个应用程序的起始地址，数组大小为 MAX_APP_NUM + 1，以便存储最后一个应用程序的结束地址
            let app_start_raw: &[usize] =
                core::slice::from_raw_parts(num_app_ptr.add(1), num_app + 1); // 从 num_app_ptr 的下一个地址开始，读取 num_app + 1 个 usize 值，这些值分别是每个应用程序的起始地址和最后一个应用程序的结束地址
            app_start[..=num_app].copy_from_slice(app_start_raw); // 将读取到的应用程序起始地址和结束地址复制到 app_start 数组中，使用 copy_from_slice 来进行复制
            AppManager {
                num_app,
                current_app: 0,
                app_start,
            }
        })
    };
}

/// init batch subsystem
pub fn init() {
    print_app_info();
}

/// print apps info
pub fn print_app_info() {
    APP_MANAGER.exclusive_access().print_app_info();
}

/// run next app
pub fn run_next_app() -> ! {
    let mut app_manager = APP_MANAGER.exclusive_access();
    let current_app = app_manager.get_current_app();
    app_manager.load_app(current_app);
    app_manager.move_to_next_app();
    drop(app_manager); // 释放对 APP_MANAGER 的独占访问权限，以便其他部分的代码能够继续访问和管理应用程序的信息
    // before this we have to drop local variables related to resources manually
    // and release the resources
    unsafe extern "C" {
        unsafe fn __restore(cx_addr: usize);
    }
    unsafe {
        __restore(KERNEL_STACK.push_context(TrapContext::app_init_context(
            APP_BASE_ADDRESS,
            USER_STACK.get_sp(),
        )) as *const _ as usize);
    }
    panic!("Unreachable in batch::run_current_app!");
}

//! SBI call wrappers

use core::arch::asm;

const SBI_CONSOLE_PUTCHAR: usize = 1;
const SBI_CONSOLE_GETCHAR: usize = 2;
const SBI_SRST_EXTENSION: usize = 0x5352_5354;
const SBI_SRST_RESET: usize = 0;
const SBI_RESET_TYPE_SHUTDOWN: usize = 0;
const SBI_RESET_REASON_NONE: usize = 0;
const SBI_RESET_REASON_SYSTEM_FAILURE: usize = 1;

/// use sbi call to putchar in console (qemu uart handler)
pub fn console_putchar(c: usize) {
    sbi_call_legacy(SBI_CONSOLE_PUTCHAR, c, 0, 0);
}

/// use sbi call to getchar from console (qemu uart handler)
#[allow(unused)]
pub fn console_getchar() -> usize {
    sbi_call_legacy(SBI_CONSOLE_GETCHAR, 0, 0, 0)
}

/// use sbi call to shutdown the kernel
pub fn shutdown(failure: bool) -> ! {
    let reason = if failure {
        SBI_RESET_REASON_SYSTEM_FAILURE
    } else {
        SBI_RESET_REASON_NONE
    };
    let _ = sbi_call(
        SBI_SRST_EXTENSION,
        SBI_SRST_RESET,
        SBI_RESET_TYPE_SHUTDOWN,
        reason,
        0,
    );
    loop {
        unsafe {
            asm!("wfi");
        }
    }
}

#[inline]
fn sbi_call_legacy(extension: usize, arg0: usize, arg1: usize, arg2: usize) -> usize {
    let ret: usize;
    unsafe {
        asm!(
            "ecall",
            inlateout("a0") arg0 => ret,
            in("a1") arg1,
            in("a2") arg2,
            in("a7") extension,
        );
    }
    ret
}

#[inline]
fn sbi_call(extension: usize, function: usize, arg0: usize, arg1: usize, arg2: usize) -> isize {
    let error: isize;
    unsafe {
        asm!(
            "ecall",
            inlateout("a0") arg0 as isize => error,
            in("a1") arg1,
            in("a2") arg2,
            in("a6") function,
            in("a7") extension,
        );
    }
    error
}

//! SBI console driver, for text output

use crate::sbi::console_putchar;
use core::fmt::{self, Write};

struct Stdout;

impl Write for Stdout {
    fn write_str(&mut self, s: &str) -> fmt::Result {
        for c in s.chars() {
            console_putchar(c as usize);
        }
        Ok(())
    }
}

pub fn print(args: fmt::Arguments) {
    Stdout.write_fmt(args).unwrap();
}

/// Write one byte to the kernel console.
pub fn putchar(byte: u8) {
    console_putchar(byte as usize);
}

/// print string macro
#[macro_export]
macro_rules! print {
    ($fmt: literal $(, $($arg: tt)+)?) => {
        $crate::console::print(format_args!($fmt $(, $($arg)+)?));
    }
}

/// println string macro
#[macro_export]
macro_rules! println {
    ($fmt: literal $(, $($arg: tt)+)?) => {
        $crate::console::print(format_args!(concat!($fmt, "\n") $(, $($arg)+)?));
    }
}

