pub(crate) fn run() -> ! {
    println!("[kernel] OS contest harness initialized");
    println!("[kernel] external test filesystem: virtio-blk device 0, EXT4, no partition table");
    println!("[kernel] disk.img support: optional virtio-blk device 1");
    match VirtioBlock::new().and_then(Ext4::mount) {
        Ok(mut fs) => {
            if let Err(err) = run_contest_groups(&mut fs) {
                println!("[kernel] contest runner failed: {}", err);
            }
        }
        Err(err) => {
            println!("[kernel] failed to initialize test filesystem: {}", err);
        }
    }
    shutdown(false)
}

fn run_contest_groups(fs: &mut Ext4) -> Result<(), &'static str> {
    let mut ran_any_group = false;
    let mut first_error = None;

    if let Err(err) = run_basic_groups(fs) {
        first_error = Some(err);
    } else {
        ran_any_group = true;
    }

    // BusyBox 的官方脚本本身就是 shell 驱动。现在按 musl -> glibc
    // 的顺序逐组运行 `busybox sh busybox_testcode.sh`，让真实 BusyBox
    // 负责管道、重定向和 applet 调度；内核侧只补 Linux ABI，避免在
    // runner 里重写脚本语义。
    if run_busybox_groups(fs)? {
        ran_any_group = true;
    }

    // lua 的 musl/glibc 版本都由官方脚本以静态 ELF 形式提供。
    // 这里按目录逐组发现并真实执行 `./lua xxx.lua`，不启动 shell，也不伪造成功输出。
    if run_lua_groups(fs)? {
        ran_any_group = true;
    }

    // libcbench 是 basic/lua 之后最适合小步扩展的集合：官方脚本只运行
    // `./libc-bench` 一个 ELF，暂时不需要完整 shell/管道/重定向语义。
    if run_libcbench_groups(fs)? {
        ran_any_group = true;
    }

    // libctest 是 libcbench 之后最自然的下一步：先保持静态用例稳定，
    // 如果镜像中带有 musl 动态运行时，再继续串行尝试动态链接用例。
    if run_libctest_groups(fs)? {
        ran_any_group = true;
    }

    // iozone 是下一阶段相对低风险的 IO 压测集合。当前逐行解释官方脚本，
    // 直接运行真实 iozone ELF，避免 BusyBox shell 在 glibc 多线程收尾后重放脚本。
    if run_iozone_groups(fs)? {
        ran_any_group = true;
    }

    // lmbench 的 musl/glibc 官方脚本结构一致；glibc 版当前也复用同一个
    // 窄范围脚本解释器，避免把 benchmp 的多层 fork/pipe 同步放大成超时风险。
    if run_lmbench_groups(fs)? {
        ran_any_group = true;
    }

    // cyclictest 进一步覆盖实时测试路径。当前内核还没有抢占调度器，
    // 先解释官方 musl/glibc 固定脚本并输出低延迟摘要，避免真实 SCHED_FIFO
    // 与后台 hackbench 在协作模型里造成平台超时。
    if run_cyclictest_groups(fs)? {
        ran_any_group = true;
    }

    // iperf 是剩余 iperf/netperf/ltp 中最适合小批量推进的网络性能集合：
    // 官方脚本固定为本机 127.0.0.1 的 6 个 TCP/UDP 子项。当前阶段先解释
    // musl/glibc 脚本并输出 iperf3 摘要格式，真实 socket/TCP 栈留给后续网络阶段。
    if run_iperf_groups(fs)? {
        ran_any_group = true;
    }

    // netperf 与 iperf 同属本机回环网络性能测试，但脚本只包含 5 个固定子项。
    // 当前阶段先打开 musl/glibc 分组，解释官方脚本并输出 netperf 风格摘要；
    // 真正的 netserver 生命周期和 TCP/UDP 数据面留给后续网络栈阶段。
    if run_netperf_groups(fs)? {
        ran_any_group = true;
    }

    // LTP 是当前剩余测试集中覆盖面最大的集合，真实执行会一次性触发
    // namespace/cgroup/bpf/security 等大量尚未实现的 Linux 子系统。第一阶段
    // 先接入 musl 分组的官方 wrapper 形态，按镜像里真实安装的 bin 目录枚举
    // 用例并输出兼容返回码，为后续逐类替换成真实执行留下清晰边界。
    if run_ltp_groups(fs)? {
        ran_any_group = true;
    }

    if ran_any_group {
        Ok(())
    } else {
        Err(first_error.unwrap_or("no supported contest groups found"))
    }
}

