/// Clear BSS segment.
fn clear_bss() {
    unsafe extern "C" {
        safe fn sbss();
        safe fn ebss();
    }
    unsafe {
        let start = sbss as *const () as usize;
        let end = ebss as *const () as usize;
        core::slice::from_raw_parts_mut(start as *mut u8, end - start).fill(0);
    }
}

/// Rust entry point of the LoongArch64 kernel.
#[unsafe(no_mangle)]
pub fn rust_main() -> ! {
    clear_bss();
    println!("[kernel-la] OSKernel2026 LoongArch64 booting");
    trap::init();
    platform::run();
}

//! LoongArch64 CSR helpers used by the contest kernel.

use core::arch::asm;

const CRMD_IE: usize = 1 << 2;
const ECFG_VS_DIRECT: usize = 0;
const ECFG_LIE_ALL: usize = 0x1fff;
const EUEN_FPE: usize = 1 << 0;
const PRMD_PIE: usize = 1 << 2;
const PRMD_PPLV_USER: usize = 3;

/// `PRMD` value used by `ertn` to enter userspace.
#[inline]
pub const fn user_prmd() -> usize {
    PRMD_PPLV_USER | PRMD_PIE
}

/// `PRMD` value used by `ertn` to resume kernel code.
#[inline]
pub const fn kernel_prmd() -> usize {
    0
}

/// Write the exception entry.
#[inline]
pub unsafe fn write_stvec(addr: usize) {
    unsafe {
        let mut value = addr;
        asm!("csrwr {0}, 0xc", inout(reg) value => _, options(nostack, preserves_flags));
        value = ECFG_VS_DIRECT | ECFG_LIE_ALL;
        asm!("csrwr {0}, 0x4", inout(reg) value => _, options(nostack, preserves_flags));
        let mut crmd: usize;
        asm!("csrrd {0}, 0x0", out(reg) crmd, options(nostack, preserves_flags));
        crmd |= CRMD_IE;
        asm!("csrwr {0}, 0x0", inout(reg) crmd => _, options(nostack, preserves_flags));
        let euen = EUEN_FPE;
        asm!("csrwr {0}, 0x2", inout(reg) euen => _, options(nostack, preserves_flags));
    }
}

/// Read the LoongArch exception status.
#[inline]
pub fn read_scause() -> usize {
    let bits: usize;
    unsafe {
        asm!("csrrd {0}, 0x5", out(reg) bits, options(nostack, preserves_flags));
    }
    bits
}

/// Read the bad virtual address register.
#[inline]
pub fn read_stval() -> usize {
    let bits: usize;
    unsafe {
        asm!("csrrd {0}, 0x7", out(reg) bits, options(nostack, preserves_flags));
    }
    bits
}

/// Read the stable counter.
#[inline]
pub fn read_time() -> usize {
    let bits: usize;
    unsafe {
        asm!("rdtime.d {0}, $r0", out(reg) bits, options(nostack, preserves_flags));
    }
    bits
}

/// Install the userspace address space.
///
/// This is still a staging hook. The RISC-V implementation uses Sv39 `satp`;
/// LoongArch needs a native page-table/TLB backend before user ELFs can run
/// with the same fidelity.
#[inline]
pub unsafe fn write_satp(bits: usize) {
    let _ = bits;
    unsafe {
        asm!("dbar 0", options(nostack, preserves_flags));
    }
}

//! LoongArch fallback kernel used only when the Rust `core` target is unavailable.
//!
//! 平台评测的 `make all` 要求同时产出 `kernel-rv` 和 `kernel-la`。部分环境
//! 没有预装 `loongarch64-unknown-none` 的 `core`，并且可能无法联网执行
//! `-Zbuild-std`。这个极小 no_core 程序只作为 LoongArch 构建兜底，避免
//! RISC-V 评测入口被 LoongArch 工具链环境问题阻塞。

#![allow(internal_features)]
#![feature(no_core, lang_items)]
#![no_core]
#![no_main]

/// `Sized` 的底层层级 lang item，no_core 下需要由当前 crate 显式提供。
#[lang = "pointee_sized"]
trait PointeeSized {}

/// `Sized` 的中间层级 lang item。
#[lang = "meta_sized"]
trait MetaSized: PointeeSized {}

/// 让编译器能够处理普通定长类型的最小 `Sized` lang item。
#[lang = "sized"]
trait Sized: MetaSized {}

/// LoongArch 兜底入口。
///
/// 这个入口不承诺通过 LoongArch 运行测试，只保证在缺少 LoongArch Rust
/// 标准库目标时仍能生成合法 ELF；如果它被误启动，会尽量写电源控制寄存器
/// 主动退出，避免长时间占住评测队列。
#[unsafe(no_mangle)]
pub extern "C" fn _start() -> ! {
    unsafe {
        // QEMU LoongArch virt 机器的 GED sleep control 寄存器；0x34 表示 S5
        // poweroff 请求，与正常 os-la 骨架里的 shutdown 常量保持一致。
        *(0x100e_001c as *mut u8) = 0x34;
    }
    loop {}
}

