pub fn sys_socket(domain: usize, socket_type: usize, _protocol: usize) -> isize {
    let base_type = socket_type & SOCK_TYPE_MASK;
    if base_type != SOCK_DGRAM
        && base_type != SOCK_STREAM
        && base_type != SOCK_RAW
        && base_type != SOCK_SEQPACKET
    {
        return EINVAL;
    }
    if domain == 0 {
        return EAFNOSUPPORT;
    }
    let domain = domain as u16;
    match domain {
        AF_INET | AF_INET6 => match (base_type, _protocol) {
            (SOCK_DGRAM, 0 | 17 | 136) | (SOCK_STREAM, 0 | 6 | 132) => {}
            // 当前没有 raw socket；LTP socket01 期望协议族支持但协议组合不支持。
            _ => return EPROTONOSUPPORT,
        },
        AF_UNIX => {
            if base_type == SOCK_RAW {
                return EPROTONOSUPPORT;
            }
            if _protocol != 0 {
                return EPROTONOSUPPORT;
            }
        }
        AF_NETLINK => {
            // musl 的 getgrgid()/getpwnam() 环境探测可能尝试打开 netlink。
            // 只要 socket/bind/close 能走通，就不会把 NSS 查询误判为 EAFNOSUPPORT。
            if base_type != SOCK_RAW && base_type != SOCK_DGRAM {
                return EPROTONOSUPPORT;
            }
        }
        AF_PACKET => {
            if base_type != SOCK_DGRAM && base_type != SOCK_RAW {
                return EPROTONOSUPPORT;
            }
        }
        _ => return EAFNOSUPPORT,
    }
    let socket_index = match alloc_socket(base_type, domain) {
        Some(index) => index,
        None => return EMFILE,
    };
    let fd_flags = if socket_type & SOCK_CLOEXEC != 0 {
        FD_CLOEXEC
    } else {
        0
    };
    let status_flags = O_RDWR
        | if socket_type & SOCK_NONBLOCK != 0 {
            O_NONBLOCK
        } else {
            0
        };
    alloc_fd(FdEntry {
        kind: HANDLE_SOCKET,
        inode: 0,
        mem_index: socket_index,
        shared_offset: usize::MAX,
        offset: 0,
        path: [0; MAX_PATH],
        path_len: 0,
        fd_flags,
        status_flags,
    })
}

