pub fn sys_shutdown(fd: usize, how: usize) -> isize {
    if how > 2 {
        return EINVAL;
    }
    let index = match socket_index(fd) {
        Ok(index) => index,
        Err(err) => return err,
    };
    unsafe {
        if !SOCKETS[index].connected {
            return ENOTCONN;
        }
        if how == 0 || how == 2 {
            SOCKETS[index].packet_len = 0;
            SOCKETS[index].read_shutdown = true;
        }
        if how == 1 || how == 2 {
            SOCKETS[index].write_shutdown = true;
        }
    }
    0
}

