pub fn sys_clone(
    cx: &mut TrapContext,
    flags: usize,
    child_sp: usize,
    parent_tid: usize,
    tls: usize,
    child_tid: usize,
) -> Result<CloneResult, isize> {
    if flags & CLONE_NEWUTS != 0 && unsafe { CURRENT_EUID } != 0 {
        return Err(EPERM);
    }
    let pid = alloc_pid();
    if flags & CLONE_PARENT_SETTID != 0 {
        write_user_i32(parent_tid, pid)?;
    }
    if flags & CLONE_CHILD_SETTID != 0 {
        // CLONE_VM 场景下父子共享地址空间；在当前快照模型中提前写入，
        // 这样子分支和恢复后的父分支都能看到一致的 tid 初值。
        write_user_i32(child_tid, pid)?;
    }
    // BusyBox shell 会用 clone(CLONE_VM | CLONE_VFORK | SIGCHLD) 实现 vfork；
    // 它共享 VM 但不是 pthread，必须走“先跑子进程再恢复父进程”的 eager fork
    // 路径。真正的 pthread_create 会带 CLONE_THREAD，继续进入协作线程队列。
    let shares_vm = flags & CLONE_VM != 0;
    let is_thread = shares_vm && flags & CLONE_THREAD != 0;
    let (parent_pid, parent_ppid) = unsafe { (CURRENT_PID, CURRENT_PPID) };
    let child_ppid = if flags & CLONE_PARENT != 0 {
        parent_ppid
    } else {
        parent_pid
    };
    let child_tp = if flags & CLONE_SETTLS != 0 { tls } else { 0 };

    if is_thread {
        if task::should_drain_pending_thread_contexts() {
            // libcbench 会连续创建大量“创建后不 join”的空线程。这里优先回收
            // 一批尚未运行的旧线程槽，给后续 pthread_create 留出空间。
            let mut dropped = [0i32; PENDING_THREAD_TRIM_BATCH];
            let dropped_count =
                task::trim_pending_thread_contexts(PENDING_THREAD_TRIM_LIMIT, &mut dropped);
            for &dropped_pid in &dropped[..dropped_count] {
                finish_trimmed_thread(dropped_pid);
            }
        }
        // CLONE_VM 线程共享当前地址空间，不能像 fork 子进程那样恢复内存快照。
        // 这里先把子线程上下文排入协作队列；父线程完成 pthread_create 的初始化
        // 并进入 futex wait/join 等等待点后，再切过去真实执行线程体。
        record_tid_cleanup(pid, parent_pid, child_ppid, child_tp, child_tid, true);
        task::queue_thread_context(cx, pid, child_sp, child_tp).map_err(|_| EAGAIN)?;
        return Ok(CloneResult::Parent(pid as isize));
    }

    if flags & CLONE_CHILD_CLEARTID != 0 {
        record_tid_cleanup(pid, parent_pid, child_ppid, child_tp, child_tid, false);
    }

    let parent_frame = unsafe {
        ForkProcessFrame {
            parent_program_brk: PROGRAM_BRK,
            parent_exec_partial_fork: CURRENT_EXEC_PARTIAL_FORK,
            parent_pid,
            parent_ppid,
            parent_state: capture_process_state(),
        }
    };
    push_fork_process_frame(parent_frame)?;
    fs::begin_child_process(flags & CLONE_FILES != 0);
    unsafe {
        // eager fork 会直接在同一套内核全局状态里运行子分支；brk 属于
        // 进程地址空间状态，子进程的 malloc/brk 变化不能泄漏回父进程。
        PARENT_PROCESS_STATE = parent_frame.parent_state;
        PARENT_PROGRAM_BRK = parent_frame.parent_program_brk;
        PARENT_EXEC_PARTIAL_FORK = parent_frame.parent_exec_partial_fork;
        PARENT_PROCESS_PID = parent_pid;
        PARENT_PROCESS_PPID = parent_ppid;
        CURRENT_PID = pid;
        CURRENT_PPID = child_ppid;
        if flags & CLONE_NEWNET != 0 {
            CURRENT_NET_NS_ISOLATED = true;
        }
