    let full_snapshot = shares_vm || unsafe { !CURRENT_EXEC_PARTIAL_FORK };
    match task::start_child_context(cx, pid, parent_pid, child_sp, child_tp, full_snapshot) {
        Ok(child) => {
            if shares_vm && flags & CLONE_VFORK != 0 && unsafe { LTP_CLONE_VM_VFORK_COMPAT } {
                task::disable_current_child_memory_restore();
            }
            if shares_vm && flags & CLONE_NEWNET != 0 {
                task::disable_current_child_memory_restore();
            }
            Ok(CloneResult::Switch(child))
        }
        Err(_) => {
            fs::finish_child_process();
            if let Some(frame) = pop_fork_process_frame() {
                restore_fork_process_frame(frame);
            }
            Err(EINVAL)
        }
    }
}

