fn run_ltp_case_list(
    fs: &mut Ext4,
    bin_inode: u32,
    group_root: u32,
    cases: &[&str],
) -> Result<usize, &'static str> {
    let mut count = 0usize;
    for run_deferred_storage in [false, true] {
        for case_name in cases {
            if is_ltp_deferred_storage_case(case_name) != run_deferred_storage {
                continue;
            }
            if run_ltp_one_case(fs, bin_inode, group_root, case_name)? {
                count += 1;
            }
        }
    }
    Ok(count)
}

fn is_ltp_deferred_storage_case(case_name: &str) -> bool {
    case_name.starts_with("dio")
        || ltp_network_compat_bridge_case(case_name).is_some()
        || ltp_mm_compat_bridge_case(case_name).is_some()
        || ltp_scheduler_compat_bridge_case(case_name).is_some()
        || ltp_device_compat_bridge_case(case_name).is_some()
        || ltp_syscall_compat_bridge_case(case_name).is_some()
        || case_name.starts_with("fsx")
        || case_name.starts_with("gf")
        || case_name.starts_with("rwtest")
        || case_name.starts_with("test_robind")
        || case_name.starts_with("fs_bind")
        || case_name.starts_with("ftest")
        || case_name.starts_with("fs_perms")
        || case_name.starts_with("stream")
        || case_name.starts_with("binfmt_misc")
        || matches!(
            case_name,
            "fs_di"
                | "fs_inod01"
                | "linker01"
                | "iogen01"
                | "fs_racer"
                | "quota_remount_test01"
                | "isofs"
                | "fs_fill"
