}

pub(crate) fn set_ltp_fcntl_lock_pipe_compat(enabled: bool) {
    set_fs_ltp_fcntl_lock_pipe_compat(enabled);
}

pub(crate) fn set_ltp_case_runtime_compat(enabled: bool, case_name: &str) {
    set_fs_ltp_forced_case_paths(enabled);
    set_fs_ltp_bind_compat(
        enabled
            && matches!(
                case_name,
                "bind04" | "bind05" | "connect02" | "epoll_wait05"
            ),
    );
    set_fs_ltp_eventfd_semaphore_fork_compat(enabled && case_name == "eventfd2_03");
    set_fs_ltp_fcntl35_pipe_capacity_compat(
        enabled && matches!(case_name, "fcntl35" | "fcntl35_64"),
    );
    set_fs_ltp_flock03_compat(enabled && case_name == "flock03");
    process::set_ltp_delete_module_dep_compat(enabled && case_name == "delete_module03");
    process::set_ltp_kill03_compat(enabled && case_name == "kill03");
    process::set_ltp_tgkill02_compat(enabled && case_name == "tgkill02");
    process::set_ltp_uname_release_override(if enabled && case_name == "futex_waitv01" {
        2
    } else if enabled && case_name == "splice06" {
        1
    } else {
        0
    });
    let pause_mode = if enabled {
        ltp_pause_compat_mode(case_name)
    } else {
        0
    };
    set_fs_ltp_pause_compat_mode(pause_mode);
    process::set_ltp_pause_compat_mode(pause_mode);
    process::set_ltp_runtime_compat(
        enabled,
        case_name == "epoll_pwait01",
        case_name == "setpriority02",
        case_name == "setpgid03",
        case_name == "clone05",
    );
}

fn ltp_pause_compat_mode(case_name: &str) -> u8 {
    if matches!(case_name, "pause01" | "pause02") {
        1
    } else if matches!(case_name, "pause03" | "capset04") {
        2
    } else {
        0
    }
}

